namespace sv_edae1c2c1b0d4874ac2872abd758b045.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> Updates);

public record StatusUpdate(DateTimeOffset Timestamp, string Description);

using sv_edae1c2c1b0d4874ac2872abd758b045.Client.Services;

namespace sv_edae1c2c1b0d4874ac2872abd758b045.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            "TRK-001",
            "In Transit",
            "Chicago, IL",
            DateTimeOffset.UtcNow.AddDays(2),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddDays(-3), "Package picked up from sender"),
                new(DateTimeOffset.UtcNow.AddDays(-2), "Arrived at sorting facility - New York, NY"),
                new(DateTimeOffset.UtcNow.AddDays(-1), "Departed sorting facility - New York, NY"),
                new(DateTimeOffset.UtcNow.AddHours(-6), "Arrived at distribution center - Chicago, IL")
            }),
        ["TRK-002"] = new ShipmentDetails(
            "TRK-002",
            "Delivered",
            "San Francisco, CA",
            DateTimeOffset.UtcNow.AddDays(-1),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddDays(-5), "Package picked up from sender"),
                new(DateTimeOffset.UtcNow.AddDays(-4), "In transit - Denver, CO"),
                new(DateTimeOffset.UtcNow.AddDays(-2), "Out for delivery - San Francisco, CA"),
                new(DateTimeOffset.UtcNow.AddDays(-1), "Delivered - Left at front door")
            }),
        ["TRK-003"] = new ShipmentDetails(
            "TRK-003",
            "Processing",
            "Seattle, WA",
            DateTimeOffset.UtcNow.AddDays(5),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddHours(-2), "Order confirmed, preparing shipment")
            })
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_edae1c2c1b0d4874ac2872abd758b045.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment details for @TrackingNumber&hellip;</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger">
        <p>@_errorMessage</p>
        <button class="btn btn-primary" @onclick="Retry">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Status Updates</h3>
    <ul>
        @foreach (var update in _shipment.Updates)
        {
            <li><strong>@update.Timestamp.ToString("g")</strong> &mdash; @update.Description</li>
        }
    </ul>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; do nothing.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task Retry()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

